mapper.sql:
WHERE 1 = 1

    AND B.CO_ID = #{coId}


    AND (
        B.BIZ_NM LIKE CONCAT('%', #{searchKeyword}, '%')
        OR B.BIZ_CD LIKE CONCAT('%', #{searchKeyword}, '%')
        OR B.ORDPL_NM LIKE CONCAT('%', #{searchKeyword}, '%')
    )


    AND B.BIZ_STTS_CD = #{searchBizSttsCd}


    AND B.INST_SE_CD = #{searchInstSeCd}


    AND B.BIZ_KND_CD = #{searchBizKndCd}


    AND B.BIZ_SE_CD = #{searchBizSeCd}


    AND B.OTST_YMD >= #{startYmd}


    AND B.BIZ_END_YMD <= #{endYmd}

mapper.select:
SELECT B.BIZ_ID ,B.CO_ID ,B.BIZ_CD ,B.BIZ_NM ,B.INST_SE_CD ,B.BIZ_KND_CD ,B.BIZ_SE_CD ,B.ORDPL_NM ,DATE_FORMAT(B.CTRT_YMD, '%Y-%m-%d') AS CTRT_YMD ,DATE_FORMAT(B.OTST_YMD, '%Y-%m-%d') AS OTST_YMD ,DATE_FORMAT(B.OTST_YMD, '%Y-%m-%d') AS BIZ_BGNG_YMD ,DATE_FORMAT(B.BIZ_END_YMD, '%Y-%m-%d') AS BIZ_END_YMD ,B.CTRT_AMT ,B.GIVE_MTHD_CN ,DATE_FORMAT(B.GIVE_DDT_YMD, '%Y-%m-%d') AS GIVE_DDT_YMD ,DATE_FORMAT(B.DFRP_GRNTE_BGNG_YMD, '%Y-%m-%d') AS DFRP_GRNTE_BGNG_YMD ,DATE_FORMAT(B.DFRP_GRNTE_END_YMD, '%Y-%m-%d') AS DFRP_GRNTE_END_YMD ,B.RMRK_CN ,B.BIZ_STTS_CD ,DATE_FORMAT(B.REG_DT, '%Y-%m-%d %H:%i:%s') AS REG_DT
FROM biz_info B
WHERE B.BIZ_ID = #{bizId}

mapper.update:
UPDATE biz_info
SET
     BIZ_CD = #{bizCd}
    ,BIZ_NM = #{bizNm}
    ,INST_SE_CD = #{instSeCd}
    ,BIZ_KND_CD = #{bizKndCd}
    ,BIZ_SE_CD = #{bizSeCd}
    ,ORDPL_NM = #{ordplNm}
    ,CTRT_YMD = NULLIF(#{ctrtYmd}, '')
    ,OTST_YMD = NULLIF(#{otstYmd}, '')
    ,BIZ_END_YMD = NULLIF(#{bizEndYmd}, '')
    ,CTRT_AMT = #{ctrtAmt}
    ,GIVE_MTHD_CN = #{giveMthdCn}
    ,GIVE_DDT_YMD = NULLIF(#{giveDdtYmd}, '')
    ,DFRP_GRNTE_BGNG_YMD = NULLIF(#{dfrpGrnteBgngYmd}, '')
    ,DFRP_GRNTE_END_YMD = NULLIF(#{dfrpGrnteEndYmd}, '')
    ,RMRK_CN = #{rmrkCn}
    ,BIZ_STTS_CD = #{bizSttsCd}
WHERE BIZ_ID = #{bizId}

mapper.select:
SELECT B.BIZ_ID ,B.CO_ID ,B.BIZ_CD ,B.BIZ_NM ,B.INST_SE_CD ,B.BIZ_KND_CD ,B.BIZ_SE_CD ,B.ORDPL_NM ,DATE_FORMAT(B.CTRT_YMD, '%Y-%m-%d') AS CTRT_YMD ,DATE_FORMAT(B.OTST_YMD, '%Y-%m-%d') AS OTST_YMD ,DATE_FORMAT(B.OTST_YMD, '%Y-%m-%d') AS BIZ_BGNG_YMD ,DATE_FORMAT(B.BIZ_END_YMD, '%Y-%m-%d') AS BIZ_END_YMD ,B.CTRT_AMT ,B.GIVE_MTHD_CN ,DATE_FORMAT(B.GIVE_DDT_YMD, '%Y-%m-%d') AS GIVE_DDT_YMD ,DATE_FORMAT(B.DFRP_GRNTE_BGNG_YMD, '%Y-%m-%d') AS DFRP_GRNTE_BGNG_YMD ,DATE_FORMAT(B.DFRP_GRNTE_END_YMD, '%Y-%m-%d') AS DFRP_GRNTE_END_YMD ,B.RMRK_CN ,B.BIZ_STTS_CD
FROM biz_info B
WHERE B.BIZ_ID = #{bizId}
